mapper.select:
SELECT id, order_id AS orderId, dish_id AS dishId, count, price,
       item_status AS itemStatus
FROM order_item WHERE id=#{id}

mapper.update:
UPDATE order_item SET item_status=#{status}
WHERE id=#{id} AND item_status=0
  AND EXISTS (
      SELECT 1 FROM orders o
      WHERE o.id=order_item.order_id AND o.pay_status=0
  )
